// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---

/**
 * Encode a compound cursor (created_at, id) as an opaque base64 JSON string.
 */
function encodeCursor(row) {
    const payload = {
        // Use ISO string so the timestamp round-trips losslessly
        createdAt: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
}

/**
 * Decode an opaque cursor back into { createdAt, id }.
 * Throws if the cursor is missing required fields or is not valid base64/JSON.
 */
function decodeCursor(cursor) {
    let decoded;
    try {
        const json = Buffer.from(cursor, 'base64').toString('utf8');
        decoded = JSON.parse(json);
    } catch (err) {
        throw new Error('Malformed cursor');
    }

    if (
        decoded === null ||
        typeof decoded !== 'object' ||
        typeof decoded.createdAt !== 'string' ||
        decoded.id === undefined ||
        decoded.id === null
    ) {
        throw new Error('Invalid cursor payload');
    }

    // Validate the timestamp actually parses
    if (Number.isNaN(Date.parse(decoded.createdAt))) {
        throw new Error('Invalid cursor timestamp');
    }

    return { createdAt: decoded.createdAt, id: decoded.id };
}

// --- Handler ---

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB
    let limit = parseInt(req.query.limit, 10) || 20;
    if (limit < 1) limit = 1;
    if (limit > 100) limit = 100;

    const after = req.query.after;

    let sql;
    let params;

    if (after) {
        let cursor;
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid pagination cursor' });
        }

        // Keyset / seek predicate matching ORDER BY created_at DESC, id DESC.
        // Row tuple comparison gives the correct compound boundary:
        //   (created_at, id) < (cursorCreatedAt, cursorId)
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1::timestamptz, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        // Fetch one extra row (N+1 trick) to detect whether more pages exist
        params = [cursor.createdAt, cursor.id, limit + 1];
    } else {
        // First page: no cursor filter
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // If we got limit + 1 rows, there is at least one more page.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor =
        hasMore && posts.length > 0
            ? encodeCursor(posts[posts.length - 1])
            : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}
```

## Notes on the implementation

- **Tuple comparison `(created_at, id) < ($1, $2)`** — PostgreSQL evaluates row-value comparisons lexicographically, which is exactly the compound boundary you want for `ORDER BY created_at DESC, id DESC`. It's equivalent to `created_at < $1 OR (created_at = $1 AND id < $2)` but cleaner and index-friendly. The `id` tiebreaker guarantees a stable, total ordering even when many posts share a `created_at`.
- **`$1::timestamptz` cast** — the cursor's timestamp arrives as a string, so the cast makes the comparison and index usage unambiguous. (Use `timestamp` instead if your column is `timestamp without time zone`.)
- **N+1 trick** — we request `limit + 1` rows; if that many come back, we know there's another page, then slice off the extra row before responding so the client always gets at most `limit` posts.
- **Graceful cursor handling** — `decodeCursor` throws on bad base64, bad JSON, or a missing/invalid payload, and the handler turns that into a `400`.

## Why cursor-based is superior here

1. **Consistent performance at scale.** `OFFSET N` forces PostgreSQL to scan and discard the first N rows on every request, so deep pages get linearly slower (page 10,000 reads 200k rows to return 20). The keyset `WHERE (created_at, id) < (...)` does an index seek straight to the boundary, so page 1 and page 10,000 cost the same — assuming an index on `(created_at DESC, id DESC)` (with `published` filterable, ideally a partial or composite index).
2. **No skipped or duplicated rows.** With offset pagination, rows inserted or deleted between requests shift the window, causing items to be repeated or missed across pages. A cursor anchors to a specific `(created_at, id)` position, so concurrent writes don't corrupt the result stream.
3. **Dropping `COUNT(*)` removes an expensive full scan.** On large tables an exact count is costly and rarely needed for infinite-scroll/feed UIs; `hasMore` answers the only question the client actually needs.

**Trade-off to be aware of:** cursor pagination doesn't support random jumps to an arbitrary page number (no "go to page 50"), which is why it's ideal for feeds/infinite scroll but not for classic numbered pagination UIs.

One thing worth confirming for your setup: make sure an index exists matching the sort — e.g. `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;` — otherwise the keyset query still does a sequential scan and you lose the main performance benefit.

