// ─── Cursor helpers ──────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque, URL-safe base64 cursor string.
 * Uses base64url (no +/= chars) so the cursor can be dropped directly into a
 * query-string without additional percent-encoding.
 */
function encodeCursor(createdAt, id) {
    const payload = JSON.stringify({
        // Normalise to ISO string so the round-trip through JSON is lossless
        // regardless of whether the pg driver returns a Date object or a string.
        created_at: createdAt instanceof Date ? createdAt.toISOString() : createdAt,
        id,
    });
    return Buffer.from(payload).toString('base64url');
}

/**
 * Decodes a cursor string.  Returns null (do NOT throw) on any failure so the
 * caller can return a clean 400 to the client instead of a 500.
 */
function decodeCursor(cursor) {
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        const parsed = JSON.parse(json);

        // Validate shape — both fields are required.
        if (typeof parsed.created_at !== 'string' || parsed.id == null) {
            return null;
        }

        // Confirm created_at is a parseable timestamp.
        if (isNaN(Date.parse(parsed.created_at))) {
            return null;
        }

        return parsed; // { created_at: string (ISO), id: number }
    } catch {
        return null;
    }
}

// ─── Route handler ───────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // ── 1. Parse & validate inputs ──────────────────────────────────────────

    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const afterParam = req.query.after;

    let cursor = null; // { created_at: string, id: number } | null

    if (afterParam !== undefined) {
        cursor = decodeCursor(afterParam);
        if (cursor === null) {
            return res.status(400).json({
                error: 'Invalid cursor. The `after` parameter is malformed or has been tampered with.',
            });
        }
    }

    // ── 2. Query (LIMIT N+1 — no OFFSET, no COUNT) ──────────────────────────
    //
    // Compound inequality for (created_at DESC, id DESC):
    //   next page = rows where (created_at, id) is "less than" the cursor pair,
    //   meaning either created_at is strictly older, or same timestamp but lower id.
    //
    //   (created_at < $cursor_ts) OR (created_at = $cursor_ts AND id < $cursor_id)
    //
    // Fetching limit+1 rows lets us detect whether another page exists without
    // a separate COUNT(*) scan.

    let result;

    if (cursor) {
        // Pages 2, 3, … — filter to rows that come after the cursor position.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (
                      created_at < $1
                      OR (created_at = $1 AND id < $2)
                    )
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1]
        );
    } else {
        // First page — no cursor filter at all.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]
        );
    }

    // ── 3. Determine hasMore and slice rows back to `limit` ─────────────────

    const hasMore = result.rows.length > limit;
    const posts = hasMore ? result.rows.slice(0, limit) : result.rows;

    // ── 4. Build the next cursor from the LAST row we're actually returning ──

    let nextCursor = null;
    if (hasMore) {
        const lastPost = posts[posts.length - 1];
        nextCursor = encodeCursor(lastPost.created_at, lastPost.id);
    }

    // ── 5. Respond ───────────────────────────────────────────────────────────

    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,   // null on the final page — client should stop paginating
            limit,
        },
    });
}
```

